1	import {
2	  ImageModelV3,
3	  LanguageModelV3Prompt,
4	  SharedV3Warning,
5	} from '@ai-sdk/provider';
6	import {
7	  combineHeaders,
8	  convertToBase64,
9	  createJsonResponseHandler,
10	  FetchFunction,
11	  generateId as defaultGenerateId,
12	  type InferSchema,
13	  lazySchema,
14	  parseProviderOptions,
15	  postJsonToApi,
16	  Resolvable,
17	  resolve,
18	  zodSchema,
19	} from '@ai-sdk/provider-utils';
20	import { z } from 'zod/v4';
21	import { googleFailedResponseHandler } from './google-error';
22	import {
23	  GoogleGenerativeAIImageModelId,
