29	interface GoogleGenerativeAIImageModelConfig {
30	  provider: string;
31	  baseURL: string;
32	  headers?: Resolvable<Record<string, string | undefined>>;
33	  fetch?: FetchFunction;
34	  generateId?: () => string;
35	  _internal?: {
36	    currentDate?: () => Date;
37	  };
38	}
