1	import { ImageModelV3, ImageModelV3CallOptions } from '@ai-sdk/provider';
2	import { ImageModelMiddleware } from '../types';
3	import { asArray } from '../util/as-array';
4	
5	/**
6	 * Wraps an ImageModelV3 instance with middleware functionality.
7	 * This function allows you to apply middleware to transform parameters
8	 * and wrap generate operations of an image model.
9	 *
10	 * @param options - Configuration options for wrapping the image model.
11	 * @param options.model - The original ImageModelV3 instance to be wrapped.
12	 * @param options.middleware - The middleware to be applied to the image model. When multiple middlewares are provided, the first middleware will transform the input first, and the last middleware will be wrapped directly around the model.
13	 * @param options.modelId - Optional custom model ID to override the original model's ID.
14	 * @param options.providerId - Optional custom provider ID to override the original model's provider ID.
15	 * @returns A new ImageModelV3 instance with middleware applied.
16	 */
17	export const wrapImageModel = ({
18	  model,
19	  middleware: middlewareArg,
20	  modelId,
21	  providerId,
22	}: {
23	  model: ImageModelV3;
24	  middleware: ImageModelMiddleware | ImageModelMiddleware[];
25	  modelId?: string;
26	  providerId?: string;
27	}): ImageModelV3 => {
28	  return [...asArray(middlewareArg)]
29	    .reverse()
30	    .reduce((wrappedModel, middleware) => {
31	      return doWrap({ model: wrappedModel, middleware, modelId, providerId });
32	    }, model);
33	};
34	
35	const doWrap = ({
36	  model,
37	  middleware: {
38	    transformParams,
39	    wrapGenerate,
40	    overrideProvider,
41	    overrideModelId,
42	    overrideMaxImagesPerCall,
43	  },
44	  modelId,
45	  providerId,
46	}: {
47	  model: ImageModelV3;
48	  middleware: ImageModelMiddleware;
49	  modelId?: string;
50	  providerId?: string;
51	}): ImageModelV3 => {
52	  async function doTransform({ params }: { params: ImageModelV3CallOptions }) {
53	    return transformParams ? await transformParams({ params, model }) : params;
54	  }
55	
56	  const maxImagesPerCallRaw =
57	    overrideMaxImagesPerCall?.({ model }) ?? model.maxImagesPerCall;
58	
59	  // Ensure provider implementations that rely on `this` inside `maxImagesPerCall`
60	  // keep working after the value is copied onto the wrapper object.
61	  const maxImagesPerCall =
62	    maxImagesPerCallRaw instanceof Function
63	      ? maxImagesPerCallRaw.bind(model)
64	      : maxImagesPerCallRaw;
65	
66	  return {
67	    specificationVersion: 'v3',
68	    provider: providerId ?? overrideProvider?.({ model }) ?? model.provider,
69	    modelId: modelId ?? overrideModelId?.({ model }) ?? model.modelId,
70	    maxImagesPerCall,
71	    async doGenerate(
72	      params: ImageModelV3CallOptions,
73	    ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
74	      const transformedParams = await doTransform({ params });
75	      const doGenerate = async () => model.doGenerate(transformedParams);
76	      return wrapGenerate
77	        ? wrapGenerate({
78	            doGenerate,
79	            params: transformedParams,
80	            model,
81	          })
82	        : doGenerate();
83	    },
84	  };
85	};
