Implements `ImageModelV3` interface. Key structure:

```typescript
export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string { return this.config.provider; }

  constructor(readonly modelId: PixelArtImageModelId, private readonly config: PixelArtConfig) {}

  async doGenerate({ prompt, n, size, aspectRatio, seed, providerOptions, headers, abortSignal }) {
    const warnings: SharedV3Warning[] = [];

    // Warn on unsupported features (no editing, no mask, no seed)
    if (aspectRatio != null) warnings.push({ type: 'unsupported', feature: 'aspectRatio' });
    if (seed != null) warnings.push({ type: 'unsupported', feature: 'seed' });

    // Parse provider-specific options (style, pixelDensity, size override)
    const pixelartOptions = await parseProviderOptions({ provider: 'pixelart', providerOptions, schema: pixelartImageOptions });

    // POST to /images/generations
    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({ path: '/images/generations', modelId: this.modelId }),
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        size: pixelartOptions?.size ?? size,
        style: pixelartOptions?.style,
        pixel_density: pixelartOptions?.pixelDensity,
      },
      failedResponseHandler: pixelartFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(pixelartImageResponseSchema),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.images.map(img => img.b64_json),
      warnings,
      response: { timestamp: new Date(), modelId: this.modelId, headers: responseHeaders },
    };
  }
}
